import { useState, useEffect, useCallback } from "react";
import { Link } from "react-router-dom";
import { createWallet, getBalance, getTxHistory, getStats } from "../api";

export default function Dashboard() {
  const [stats, setStats] = useState(null);
  const [wallet, setWallet] = useState(() => {
    try { return JSON.parse(localStorage.getItem("bw_wallet")); } catch { return null; }
  });
  const [balance, setBalance] = useState("0.00");
  const [history, setHistory] = useState([]);
  const [password, setPassword] = useState("");
  const [creating, setCreating] = useState(false);
  const [alert, setAlert] = useState(null);

  const showAlert = (msg, type = "success") => {
    setAlert({ msg, type });
    setTimeout(() => setAlert(null), 4000);
  };

  const loadData = useCallback(async () => {
    try {
      const s = await getStats();
      setStats(s.data);
      if (wallet) {
        const [b, h] = await Promise.all([
          getBalance(wallet.address),
          getTxHistory(wallet.address),
        ]);
        setBalance(b.data.balance.toFixed(2));
        setHistory(h.data);
      }
    } catch {}
  }, [wallet]);

  useEffect(() => {
    loadData();
    const t = setInterval(loadData, 5000);
    return () => clearInterval(t);
  }, [loadData]);

  const handleCreate = async () => {
    if (!password) return showAlert("Enter a password", "error");
    setCreating(true);
    try {
      const res = await createWallet(password);
      setWallet(res.data);
      localStorage.setItem("bw_wallet", JSON.stringify(res.data));
      showAlert("Wallet created successfully!");
      setPassword("");
    } catch { showAlert("Failed to create wallet", "error"); }
    finally { setCreating(false); }
  };

  const copyAddress = () => {
    navigator.clipboard.writeText(wallet.address);
    showAlert("Address copied to clipboard!");
  };

  const shortAddr = addr => addr ? addr.slice(0, 8) + "…" + addr.slice(-8) : "";

  if (!wallet) {
    return (
      <div style={{ maxWidth: 500, margin: "80px auto", textAlign: "center" }}>
        <div style={{ fontSize: 64, marginBottom: 20 }}>🌌</div>
        <h1 style={{ fontSize: 32, marginBottom: 12 }}>Welcome to SecureChain</h1>
        <p style={{ color: "var(--muted)", marginBottom: 40, lineHeight: 1.6 }}>
          Your gateway to the decentralized web. Create a new wallet to start sending, receiving, and mining BCW.
        </p>

        {alert && <div className={`alert alert-${alert.type}`}>{alert.msg}</div>}

        <div className="card" style={{ textAlign: "left" }}>
          <div className="form-group">
            <label className="label">Secure Password</label>
            <input
              className="input"
              type="password"
              placeholder="Enter a strong password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleCreate()}
            />
            <div className="hint">This password encrypts your private key locally. Do not lose it.</div>
          </div>
          <button className="btn btn-primary" style={{ width: "100%", padding: 18, fontSize: 18 }} onClick={handleCreate} disabled={creating}>
            {creating ? <><div className="spinner" />Creating Wallet…</> : "Create New Wallet"}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 800, margin: "0 auto" }}>
      {alert && <div className={`alert alert-${alert.type}`}>{alert.msg}</div>}

      <div className="wallet-hero">
        <div className="hero-balance-label">Total Balance</div>
        <div className="hero-balance">
          {balance} <span className="hero-currency">BCW</span>
        </div>
        <div className="hero-address" onClick={copyAddress} title="Click to copy">
          {shortAddr(wallet.address)} <span>⎘</span>
        </div>

        <div className="quick-actions">
          <Link to="/send" className="action-btn">
            <div className="action-icon-wrap">↗</div>
            <span className="action-label">Send</span>
          </Link>
          <button className="action-btn" onClick={copyAddress}>
            <div className="action-icon-wrap">↓</div>
            <span className="action-label">Receive</span>
          </button>
          <Link to="/mine" className="action-btn">
            <div className="action-icon-wrap">⛏</div>
            <span className="action-label">Mine</span>
          </Link>
        </div>
      </div>

      <div className="mini-stats-row">
        <div className="mini-stat">
          <span className="mini-stat-label">Network Blocks</span>
          <span className="mini-stat-val">{stats?.blocks ?? "—"}</span>
        </div>
        <div className="mini-stat">
          <span className="mini-stat-label">Difficulty</span>
          <span className="mini-stat-val" style={{ color: "var(--green)" }}>{stats?.difficulty ?? "—"}</span>
        </div>
        <div className="mini-stat">
          <span className="mini-stat-label">Chain Status</span>
          <span className="mini-stat-val" style={{ color: stats?.valid ? "var(--green)" : "var(--red)" }}>
            {stats == null ? "—" : stats.valid ? "Healthy" : "Invalid"}
          </span>
        </div>
      </div>

      <div className="activity-section">
        <div className="section-header">
          <h2 className="section-title">Recent Activity</h2>
          <Link to="/explorer" style={{ color: "var(--accent)", textDecoration: "none", fontSize: 14, fontWeight: 600 }}>
            View Explorer →
          </Link>
        </div>

        {history.length === 0 ? (
          <div className="card" style={{ textAlign: "center", padding: "60px 20px" }}>
            <div style={{ fontSize: 40, opacity: 0.5, marginBottom: 16 }}>📭</div>
            <h3 style={{ marginBottom: 8, fontSize: 18 }}>No transactions yet</h3>
            <p style={{ color: "var(--muted)", fontSize: 14 }}>Mine a block or receive BCW to get started.</p>
          </div>
        ) : (
          history.slice(0, 10).map((tx, i) => {
            const isMine = tx.sender === "SYSTEM" && tx.receiver === wallet.address;
            const isSend = tx.sender === wallet.address;
            const isReceive = tx.receiver === wallet.address && !isMine;

            let icon = "↓"; let iconClass = "receive"; let title = "Received"; let sign = "+";
            if (isSend) { icon = "↗"; iconClass = "send"; title = "Sent"; sign = "-"; }
            if (isMine) { icon = "⛏"; iconClass = "mine"; title = "Mined Reward"; sign = "+"; }

            return (
              <div className="tx-item" key={i}>
                <div className="tx-left">
                  <div className={`tx-icon ${iconClass}`}>{icon}</div>
                  <div className="tx-details">
                    <h4>{title}</h4>
                    <p>{isSend ? `To: ${shortAddr(tx.receiver)}` : isReceive ? `From: ${shortAddr(tx.sender)}` : "Block Reward"}</p>
                  </div>
                </div>
                <div className="tx-right">
                  <div className={`tx-amt ${sign === "+" ? "positive" : "negative"}`}>
                    {sign}{parseFloat(tx.amount).toFixed(2)} BCW
                  </div>
                  <div className="tx-status">Block #{tx.block_index}</div>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}
